function makeCounter() {
  let count = 0;                 // private — only the closure sees it
  return {
    inc: () => ++count,
    get: () => count,
  };
}
const c = makeCounter();
c.inc(); c.inc();
console.log(c.get());            // 2
console.log(typeof c.count);     // undefined (truly private)

function debounce(fn, ms) {
  let t;
  return (...args) => {
    clearTimeout(t);
    t = setTimeout(() => fn(...args), ms);
  };
}
const log = debounce(v => console.log('ran with:', v), 100);
log('a'); log('b'); log('c');   // only the last call survives
// => 'ran with: c'

function demo() {
  var fnScoped = 'function';
  if (true) {
    let blockScoped = 'block';
    console.log(blockScoped, fnScoped); // both visible here
  }
  console.log(fnScoped);                // 'function'
  try { console.log(blockScoped); }     // ReferenceError
  catch (e) { console.log(e.name); }    // 'ReferenceError'
}
demo();

const counter = {
  n: 0,
  inc() { this.n++; return this.n; },
};
