const range = {
  from: 1, to: 4,
  [Symbol.iterator]() {
    let n = this.from; const end = this.to;
    return { next: () => n <= end ? { value: n++, done: false } : { value: undefined, done: true } };
  },
};
console.log([...range]);          // [1,2,3,4]
for (const x of range) console.log('x =', x);

function getDataCb(ok, cb) {
  setTimeout(() => (ok ? cb(null, 'data') : cb(new Error('failed'))), 50);
}
const getData = (ok) => new Promise((resolve, reject) =>
  getDataCb(ok, (err, data) => (err ? reject(err) : resolve(data))));

getData(true).then(d => console.log('ok:', d));
getData(false).catch(e => console.log('caught:', e.message));

