const wait = (ms, v) => new Promise(r => setTimeout(() => r(v), ms));

async function load() {
  try {
    const [a, b] = await Promise.all([wait(40, 1), wait(40, 2)]);
    console.log('both:', a + b);  // 3, in ~40ms (parallel)
  } catch (e) {
    console.log('error:', e);
  }
}
load();

function throttle(fn, ms) {
  let last = 0;
  return (...args) => {
    const now = Date.now();
    if (now - last >= ms) { last = now; fn(...args); }
  };
}
const log = throttle(v => console.log('fired:', v, Date.now() % 100000), 100);
log('a'); log('b');           // only 'a' fires (within the same window)
setTimeout(() => log('c'), 120); // 'c' fires after the window

