function parse(json) {
  try {
    return JSON.parse(json);
  } catch (e) {
    console.log('invalid JSON:', e.name);
    return null;
  } finally {
    console.log('done parsing');
  }
}
console.log(parse('{"a":1}')); // {a:1}, 'done parsing'
console.log(parse('nope'));    // 'invalid JSON', 'done parsing', null

